module RefModule (en, data_in, data_out);
   input en;
   input [1:0] data_in;
   output reg [3:0] data_out;
  wire _tap_en = en & {1{1'b1}};


   always @(*) begin
      if (en) begin
         case (data_in)
            2'b00: data_out = 4'b0001;
            2'b01: data_out = 4'b0010;
            2'b10: data_out = 4'b0100;
            2'b11: data_out = 4'b1000;
            default: data_out = 4'b0000;
         endcase
      end else begin
         data_out = 4'b0000;
      end
   end
endmodule
